document.addEventListener('DOMContentLoaded', () => { initStickyHeader(); initScrollReveal(); initMobileMenu(); initHelpFloat(); initSearchOverlay(); initBackToTop(); initDonateBanner(); setActiveNavLink(); }); function initStickyHeader() { const header = document.querySelector('.header'); if (!header) return; const handleScroll = () => { if (window.scrollY > 50) { header.classList.add('scrolled'); } else { header.classList.remove('scrolled'); } }; window.addEventListener('scroll', handleScroll, { passive: true }); handleScroll(); } function initScrollReveal() { const reveals = document.querySelectorAll('.reveal, .reveal-left, .reveal-right, .reveal-scale'); if (!reveals.length) return; const observer = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) { entry.target.classList.add('revealed'); observer.unobserve(entry.target); } }); }, { threshold: 0.15, rootMargin: '0px 0px -50px 0px' }); reveals.forEach(el => observer.observe(el)); } function initMobileMenu() { const toggle = document.querySelector('.header__mobile-toggle'); const mobileNav = document.querySelector('.mobile-nav'); if (!toggle || !mobileNav) return; toggle.addEventListener('click', () => { toggle.classList.toggle('active'); mobileNav.classList.toggle('active'); document.body.style.overflow = mobileNav.classList.contains('active') ? 'hidden' : ''; }); const subMenuToggles = mobileNav.querySelectorAll('.mobile-nav__link[data-submenu]'); subMenuToggles.forEach(link => { link.addEventListener('click', (e) => { e.preventDefault(); const submenuId = link.getAttribute('data-submenu'); const submenu = document.getElementById(submenuId); if (submenu) { submenu.classList.toggle('active'); const arrow = link.querySelector('.arrow'); if (arrow) { arrow.style.transform = submenu.classList.contains('active') ? 'rotate(180deg)' : ''; } } }); }); const navLinks = mobileNav.querySelectorAll('.mobile-nav__submenu-link, .mobile-nav__link:not([data-submenu])'); navLinks.forEach(link => { link.addEventListener('click', () => { toggle.classList.remove('active'); mobileNav.classList.remove('active'); document.body.style.overflow = ''; }); }); } function initHelpFloat() { const helpFloat = document.querySelector('.help-float'); if (!helpFloat) return; const btn = helpFloat.querySelector('.help-float__btn'); btn.addEventListener('click', () => { helpFloat.classList.toggle('active'); }); document.addEventListener('click', (e) => { if (!helpFloat.contains(e.target)) { helpFloat.classList.remove('active'); } }); document.addEventListener('keydown', (e) => { if (e.key === 'Escape') { helpFloat.classList.remove('active'); } }); } function initSearchOverlay() { const searchBtn = document.querySelector('.header__search-btn'); const overlay = document.querySelector('.search-overlay'); if (!searchBtn || !overlay) return; const closeBtn = overlay.querySelector('.search-overlay__close'); const input = overlay.querySelector('.search-overlay__input'); searchBtn.addEventListener('click', () => { overlay.classList.add('active'); setTimeout(() => input?.focus(), 300); document.body.style.overflow = 'hidden'; }); const closeSearch = () => { overlay.classList.remove('active'); document.body.style.overflow = ''; if (input) input.value = ''; }; closeBtn?.addEventListener('click', closeSearch); overlay.addEventListener('click', (e) => { if (e.target === overlay) closeSearch(); }); document.addEventListener('keydown', (e) => { if (e.key === 'Escape' && overlay.classList.contains('active')) { closeSearch(); } }); } function initBackToTop() { const btn = document.querySelector('.back-to-top'); if (!btn) return; window.addEventListener('scroll', () => { if (window.scrollY > 500) { btn.classList.add('visible'); } else { btn.classList.remove('visible'); } }, { passive: true }); btn.addEventListener('click', () => { window.scrollTo({ top: 0, behavior: 'smooth' }); }); } function initDonateBanner() { const banner = document.querySelector('.donate-banner'); if (!banner) return; setTimeout(() => { if (window.scrollY > 600) { banner.classList.add('visible'); } }, 3000); window.addEventListener('scroll', () => { if (window.scrollY > 600) { banner.classList.add('visible'); } }, { passive: true }); const closeBtn = banner.querySelector('.donate-banner__close'); closeBtn?.addEventListener('click', () => { banner.classList.remove('visible'); banner.style.display = 'none'; }); } function setActiveNavLink() { const currentPage = window.location.pathname.split('/').pop() || 'index.html'; const navLinks = document.querySelectorAll('.header__nav-link'); navLinks.forEach(link => { const href = link.getAttribute('href'); if (href === currentPage || (currentPage === '' && href === 'index.html')) { link.classList.add('active'); } }); } function showToast(message, type = 'success') { document.querySelectorAll('.toast').forEach(t => t.remove()); const toast = document.createElement('div'); toast.className = `toast toast--${type}`; toast.innerHTML = ` <span>${type === 'success' ? '✓' : type === 'error' ? '✗' : 'ℹ'}</span> <span>${message}</span> `; document.body.appendChild(toast); requestAnimationFrame(() => { toast.classList.add('show'); }); setTimeout(() => { toast.classList.remove('show'); setTimeout(() => toast.remove(), 300); }, 4000); } document.addEventListener('click', (e) => { const link = e.target.closest('a[href^="#"]'); if (!link) return; const target = document.querySelector(link.getAttribute('href')); if (target) { e.preventDefault(); const headerHeight = document.querySelector('.header')?.offsetHeight || 80; const top = target.getBoundingClientRect().top + window.scrollY - headerHeight - 20; window.scrollTo({ top, behavior: 'smooth' }); } }); ; class HeroCarousel { constructor(element) { this.carousel = element; this.track = element.querySelector('.carousel__track'); this.slides = [...element.querySelectorAll('.carousel__slide')]; this.prevBtn = element.querySelector('.carousel__arrow--prev'); this.nextBtn = element.querySelector('.carousel__arrow--next'); this.dotsContainer = element.querySelector('.carousel__dots'); this.currentIndex = 0; this.totalSlides = this.slides.length; this.autoplayInterval = null; this.autoplayDelay = 5000; this.isTransitioning = false; this.touchStartX = 0; this.touchEndX = 0; this.minSwipeDistance = 50; this.init(); } init() { this.createDots(); this.bindEvents(); this.goToSlide(0); this.startAutoplay(); } createDots() { if (!this.dotsContainer) return; this.dotsContainer.innerHTML = ''; for (let i = 0; i < this.totalSlides; i++) { const dot = document.createElement('button'); dot.className = 'carousel__dot'; dot.setAttribute('aria-label', `Go to slide ${i + 1}`); dot.addEventListener('click', () => this.goToSlide(i)); this.dotsContainer.appendChild(dot); } this.dots = [...this.dotsContainer.querySelectorAll('.carousel__dot')]; } bindEvents() { this.prevBtn?.addEventListener('click', () => this.prev()); this.nextBtn?.addEventListener('click', () => this.next()); this.carousel.addEventListener('mouseenter', () => this.stopAutoplay()); this.carousel.addEventListener('mouseleave', () => this.startAutoplay()); this.carousel.addEventListener('touchstart', (e) => { this.touchStartX = e.changedTouches[0].screenX; this.stopAutoplay(); }, { passive: true }); this.carousel.addEventListener('touchend', (e) => { this.touchEndX = e.changedTouches[0].screenX; this.handleSwipe(); this.startAutoplay(); }, { passive: true }); this.carousel.addEventListener('keydown', (e) => { if (e.key === 'ArrowLeft') this.prev(); if (e.key === 'ArrowRight') this.next(); }); document.addEventListener('visibilitychange', () => { if (document.hidden) { this.stopAutoplay(); } else { this.startAutoplay(); } }); } goToSlide(index) { if (this.isTransitioning) return; this.isTransitioning = true; this.slides[this.currentIndex]?.classList.remove('active'); this.dots?.[this.currentIndex]?.classList.remove('active'); this.currentIndex = ((index % this.totalSlides) + this.totalSlides) % this.totalSlides; this.slides[this.currentIndex]?.classList.add('active'); this.dots?.[this.currentIndex]?.classList.add('active'); const progress = this.carousel.querySelector('.carousel__progress-fill'); if (progress) { progress.style.width = `${((this.currentIndex + 1) / this.totalSlides) * 100}%`; } setTimeout(() => { this.isTransitioning = false; }, 800); } next() { this.goToSlide(this.currentIndex + 1); } prev() { this.goToSlide(this.currentIndex - 1); } handleSwipe() { const diff = this.touchStartX - this.touchEndX; if (Math.abs(diff) > this.minSwipeDistance) { if (diff > 0) { this.next(); } else { this.prev(); } } } startAutoplay() { this.stopAutoplay(); this.autoplayInterval = setInterval(() => this.next(), this.autoplayDelay); } stopAutoplay() { if (this.autoplayInterval) { clearInterval(this.autoplayInterval); this.autoplayInterval = null; } } } document.addEventListener('DOMContentLoaded', () => { document.querySelectorAll('.carousel').forEach(el => { new HeroCarousel(el); }); }); ; class AnimatedCounter { constructor(element) { this.element = element; this.target = parseInt(element.getAttribute('data-target'), 10) || 0; this.suffix = element.getAttribute('data-suffix') || ''; this.prefix = element.getAttribute('data-prefix') || ''; this.duration = parseInt(element.getAttribute('data-duration'), 10) || 2000; this.animated = false; } animate() { if (this.animated) return; this.animated = true; const start = 0; const end = this.target; const duration = this.duration; const startTime = performance.now(); const easeOutExpo = (t) => { return t === 1 ? 1 : 1 - Math.pow(2, -10 * t); }; const update = (currentTime) => { const elapsed = currentTime - startTime; const progress = Math.min(elapsed / duration, 1); const easedProgress = easeOutExpo(progress); const current = Math.floor(start + (end - start) * easedProgress); this.element.textContent = this.prefix + this.formatNumber(current) + this.suffix; if (progress < 1) { requestAnimationFrame(update); } }; requestAnimationFrame(update); } formatNumber(num) { if (num >= 1000) { return num.toLocaleString(); } return num.toString(); } } document.addEventListener('DOMContentLoaded', () => { const counterElements = document.querySelectorAll('[data-counter]'); if (!counterElements.length) return; const counters = [...counterElements].map(el => new AnimatedCounter(el)); const observer = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) { const counter = counters.find(c => c.element === entry.target); if (counter) { const index = counters.indexOf(counter); setTimeout(() => counter.animate(), index * 150); } observer.unobserve(entry.target); } }); }, { threshold: 0.3 }); counterElements.forEach(el => observer.observe(el)); }); ; document.addEventListener('DOMContentLoaded', () => { const form = document.getElementById('contact-form'); if (!form) return; const inputs = form.querySelectorAll('.form-input, .form-textarea'); inputs.forEach(input => { if (input.value.trim()) { input.classList.add('has-value'); } input.addEventListener('focus', () => { input.parentElement.classList.add('focused'); }); input.addEventListener('blur', () => { input.parentElement.classList.remove('focused'); if (input.value.trim()) { input.classList.add('has-value'); } else { input.classList.remove('has-value'); } }); input.addEventListener('input', () => { clearFieldError(input); }); }); form.addEventListener('submit', async (e) => { e.preventDefault(); if (!validateForm(form)) return; const submitBtn = form.querySelector('.form-submit-btn'); const btnText = submitBtn.querySelector('.btn-text'); const btnLoader = submitBtn.querySelector('.btn-loader'); submitBtn.disabled = true; btnText.style.display = 'none'; btnLoader.style.display = 'inline-flex'; try { await new Promise(resolve => setTimeout(resolve, 1500)); showToast('Message sent successfully! We\'ll get back to you soon.', 'success'); form.reset(); inputs.forEach(input => input.classList.remove('has-value')); } catch (error) { showToast('Failed to send message. Please try again later.', 'error'); console.error('Form submission error:', error); } finally { submitBtn.disabled = false; btnText.style.display = 'inline'; btnLoader.style.display = 'none'; } }); }); function validateForm(form) { let isValid = true; const fields = [ { id: 'name', message: 'Please enter your full name' }, { id: 'email', message: 'Please enter a valid email address', validate: validateEmail }, { id: 'phone', message: 'Please enter a valid phone number', validate: validatePhone, optional: true }, { id: 'subject', message: 'Please enter a subject' }, { id: 'message', message: 'Please enter your message' }, ]; fields.forEach(field => { const input = form.querySelector(`#${field.id}`); if (!input) return; const value = input.value.trim(); if (!field.optional && !value) { showFieldError(input, field.message); isValid = false; } else if (value && field.validate && !field.validate(value)) { showFieldError(input, field.message); isValid = false; } }); return isValid; } function validateEmail(email) { return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email); } function validatePhone(phone) { if (!phone) return true; return /^[\+]?[\d\s\-\(\)]{7,15}$/.test(phone); } function showFieldError(input, message) { const group = input.parentElement; group.classList.add('error'); let errorEl = group.querySelector('.form-error'); if (!errorEl) { errorEl = document.createElement('span'); errorEl.className = 'form-error'; group.appendChild(errorEl); } errorEl.textContent = message; input.style.animation = 'none'; input.offsetHeight; input.style.animation = 'shake 0.4s ease'; } function clearFieldError(input) { const group = input.parentElement; group.classList.remove('error'); const errorEl = group.querySelector('.form-error'); if (errorEl) errorEl.remove(); } ;